import React, { useState } from "react";
import axios from "axios";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  ArcElement,
  RadialLinearScale,
  Filler,
  Title,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar, Line, Doughnut } from "react-chartjs-2";
import {
  LayoutDashboard,
  FileSpreadsheet,
  Search,
  BarChart2,
  FileText,
  CloudUpload,
  Settings,
  Bell,
  User,
  ChevronLeft,
  ChevronRight,
  Users,
  Target,
  Activity,
  TrendingUp,
} from "lucide-react";
import "./App.css";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  PointElement,
  LineElement,
  ArcElement,
  RadialLinearScale,
  Filler,
  Title,
  Tooltip,
  Legend
);

// ✅ API connection to Flask backend
const API_BASE = "http://localhost:5000/api";

export default function App() {
  const [activeTab, setActiveTab] = useState("dashboard");
  const [sidebarOpen, setSidebarOpen] = useState(true);
  const [loading, setLoading] = useState(false);
  const [customer, setCustomer] = useState({
    Tenure: 12,
    OrderCount: 8,
    CashbackAmount: 1500,
    DaySinceLastOrder: 7,
    HourSpendOnApp: 25,
    SatisfactionScore: 4,
    Complain: 0,
  });
  const [result, setResult] = useState(null);
  const [batchSummary, setBatchSummary] = useState(null);

  // 🔹 Single Customer Analysis
  const handleAnalyzeSingle = async () => {
    setLoading(true);
    setResult(null);
    try {
      const res = await axios.post(`${API_BASE}/analyze-single`, {
        customer_data: customer,
      });
      setResult(res.data);
      setActiveTab("results");
    } catch (err) {
      console.error("API Error:", err);
      alert("Error analyzing customer data.");
    }
    setLoading(false);
  };

  // 🔹 Batch Upload
  const handleBatchUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return alert("Please select a CSV file");
    const formData = new FormData();
    formData.append("file", file);
    setLoading(true);
    try {
      const res = await axios.post(`${API_BASE}/analyze-batch`, formData);
      setBatchSummary(res.data.summary);
      setActiveTab("reports");
    } catch (err) {
      console.error(err);
      alert("Batch upload failed");
    }
    setLoading(false);
  };

  return (
    <div className="app">
      {/* Sidebar */}
      <aside className={`sidebar ${sidebarOpen ? "open" : "closed"}`}>
        <div className="sidebar-header">
          <h2>ChurnIntel</h2>
          <button onClick={() => setSidebarOpen(!sidebarOpen)}>
            {sidebarOpen ? <ChevronLeft /> : <ChevronRight />}
          </button>
        </div>
        <nav>
          <button
            className={activeTab === "dashboard" ? "active" : ""}
            onClick={() => setActiveTab("dashboard")}
          >
            <LayoutDashboard /> {sidebarOpen && "Dashboard"}
          </button>
          <button
            className={activeTab === "analyze" ? "active" : ""}
            onClick={() => setActiveTab("analyze")}
          >
            <Search /> {sidebarOpen && "Analyze"}
          </button>
          <button
            className={activeTab === "results" ? "active" : ""}
            onClick={() => setActiveTab("results")}
          >
            <BarChart2 /> {sidebarOpen && "Results"}
          </button>
          <button
            className={activeTab === "reports" ? "active" : ""}
            onClick={() => setActiveTab("reports")}
          >
            <FileSpreadsheet /> {sidebarOpen && "Reports"}
          </button>
        </nav>
        <div className="sidebar-footer">
          <Settings />
          <Bell />
          <User />
        </div>
      </aside>

      {/* Main Content */}
      <main className="main-content">
        <header>
          <h1>
            {activeTab === "dashboard" && "Executive Dashboard"}
            {activeTab === "analyze" && "Customer Analysis"}
            {activeTab === "results" && "Churn Risk Results"}
            {activeTab === "reports" && "Reports & Insights"}
          </h1>
        </header>

        {activeTab === "dashboard" && <Dashboard />}

        {activeTab === "analyze" && (
          <div className="analyze">
            <h2>Single Customer Prediction</h2>
            <div className="form-grid">
              {Object.keys(customer).map((key) => (
                <label key={key}>
                  {key}
                  <input
                    type="number"
                    value={customer[key]}
                    onChange={(e) =>
                      setCustomer({ ...customer, [key]: e.target.value })
                    }
                  />
                </label>
              ))}
            </div>
            <button
              className="btn"
              onClick={handleAnalyzeSingle}
              disabled={loading}
            >
              {loading ? "Analyzing..." : "Run Prediction"}
            </button>

            <h2>Batch Upload (.CSV)</h2>
            <input type="file" accept=".csv" onChange={handleBatchUpload} />
          </div>
        )}

        {activeTab === "results" && result && (
          <Results result={result} setActiveTab={setActiveTab} />
        )}

        {activeTab === "reports" && batchSummary && (
          <Reports summary={batchSummary} />
        )}
      </main>
    </div>
  );
}

