// ======================= Results =======================
function Results({ result }) {
  const prob = (result.probability * 100).toFixed(2);
  const risk = result.risk_level;

  return (
    <div className="results">
      <div className={`risk-banner ${risk.toLowerCase()}`}>
        <h2>{risk} RISK</h2>
        <p>Churn Probability: {prob}%</p>
      </div>

      <div className="chart-container">
        <h3>Top Risk Drivers</h3>
        <Bar
          data={{
            labels: result.feature_contributions.map((f) => f.Feature),
            datasets: [
              {
                data: result.feature_contributions.map((f) => f.Contribution),
                backgroundColor: "#7c3aed",
              },
            ],
          }}
          options={{ plugins: { legend: { display: false } } }}
        />
      </div>

      <div className="report-section">
        <h3>Business Impact</h3>
        <p>
          Potential Revenue Loss: ₹
          {result.business_impact.potential_revenue_loss.toFixed(2)}
        </p>
        <p>
          ROI of Retention: {result.business_impact.roi_retention.toFixed(2)}x
        </p>
      </div>
    </div>
  );
}

// ======================= Reports =======================
function Reports({ summary }) {
  return (
    <div className="reports">
      <h2>Batch Summary</h2>
      <p>Total Customers: {summary.total_customers}</p>
      <p>High Risk %: {summary.high_risk_percentage.toFixed(2)}%</p>
      <p>Potential Loss: ₹{summary.total_potential_loss.toFixed(2)}</p>
      <p>ROI Retention: {summary.roi_retention.toFixed(2)}x</p>
    </div>
  );
}
